+export function createCartState() {
+  return {
+    items: []
+  };
+}
+
+export function addItem(state, item) {
+  const existingItem = state.items.find(({ id }) => id === item.id);
+
+  if (existingItem) {
+    return {
+      ...state,
+      items: state.items.map((cartItem) =>
+        cartItem.id === item.id
+          ? { ...cartItem, quantity: cartItem.quantity + 1 }
+          : cartItem
+      )
+    };
+  }
+
+  return {
+    ...state,
+    items: [...state.items, { ...item, quantity: 1 }]
+  };
+}
+
+export function updateItemQuantity(state, itemId, quantity) {
+  if (quantity <= 0) {
+    return removeItem(state, itemId);
+  }
+
+  return {
+    ...state,
+    items: state.items.map((item) =>
+      item.id === itemId ? { ...item, quantity } : item
+    )
+  };
+}
+
+export function changeQuantity(state, itemId, delta) {
+  const target = state.items.find((item) => item.id === itemId);
+
+  if (!target) {
+    return state;
+  }
+
+  return updateItemQuantity(state, itemId, target.quantity + delta);
+}
+
+export function removeItem(state, itemId) {
+  return {
+    ...state,
+    items: state.items.filter((item) => item.id !== itemId)
+  };
+}
+
+export function clearCart() {
+  return createCartState();
+}
+
+export function getCartSummary(state) {
+  return state.items.reduce(
+    (summary, item) => ({
+      count: summary.count + item.quantity,
+      total: summary.total + item.price * item.quantity
+    }),
+    { count: 0, total: 0 }
+  );
+}
+
+export function formatWon(amount) {
+  return `₩${amount.toLocaleString("ko-KR")}`;
+}
